[ApiController]
[Route("api/[controller]")]
public class InvoicesController : ControllerBase
{
    private readonly IInvoiceService _invoiceService;
    private readonly IUserContext _userContext;

    public InvoicesController(IInvoiceService invoiceService, IUserContext userContext)
    {
        _invoiceService = invoiceService;
        _userContext = userContext;
    }

    [HttpGet("{id}")]
    public async Task<ActionResult<InvoiceDto>> GetInvoice(string id)
    {
        var invoice = await _invoiceService.GetInvoiceByIdAsync(id, _userContext.UserId);
        
        if (invoice == null)
        {
            return NotFound();
        }

        if (!await _invoiceService.IsUserAuthorizedForInvoiceAsync(invoice, _userContext.UserId))
        {
